document.addEventListener('DOMContentLoaded',function(){let tocTitle=document.querySelector('.pillar--toc_title');let body=document.body;if(body.classList.contains('page-template-pillar')){tocTitle.addEventListener('click',function(e){e.preventDefault();let tocWrap=this.parentElement;tocWrap.classList.toggle('open')});const sections=document.querySelectorAll('.pillar--section');const tocParent=document.querySelector('.pillar--toc_list');const tocLinks=document.querySelectorAll('.pillar--toc_list a');let lastActiveIndex=null;function TOCClicketEvents(){tocLinks.forEach(function(link){link.addEventListener('click',function(e){e.preventDefault();const target_id=link.getAttribute('href');const section_target=document.getElementById(target_id.substring(1));section_target.scrollIntoView({behavior:"smooth"})})})}
function onScroll(){let currentSectionIndex=null;for(let i=0;i<sections.length;i++){const sectionTop=sections[i].getBoundingClientRect().top;if(sectionTop<=200){currentSectionIndex=i}else{break}}
if(lastActiveIndex!==currentSectionIndex){if(lastActiveIndex!==null){tocLinks[lastActiveIndex].classList.remove('active')}
if(currentSectionIndex!==null){tocLinks[currentSectionIndex].classList.add('active');if(!isElementInView(tocParent,tocLinks[currentSectionIndex])){scrollElementIntoView(tocParent,tocLinks[currentSectionIndex])}}
lastActiveIndex=currentSectionIndex}}
function wrapTablesInDiv(){var sectionContents=document.querySelectorAll('.pillar--section_content');sectionContents.forEach(function(sectionContent){var tables=sectionContent.querySelectorAll('table');tables.forEach(function(table){var div=document.createElement('div');div.className='responsive-table';table.parentNode.insertBefore(div,table);div.appendChild(table)})})}
function isElementInView(parent,element){const parentRect=parent.getBoundingClientRect();const elementRect=element.getBoundingClientRect();const inView=(elementRect.top>=parentRect.top&&elementRect.left>=parentRect.left&&elementRect.bottom<=parentRect.bottom&&elementRect.right<=parentRect.right);return inView}
function scrollElementIntoView(parent,element){const parentRect=parent.getBoundingClientRect();const elementRect=element.getBoundingClientRect();const offsetTop=elementRect.top-parentRect.top+parent.scrollTop;const scrollOptions={behavior:'smooth'};if(elementRect.top<parentRect.top){parent.scrollTo({top:offsetTop,...scrollOptions})}else if(elementRect.bottom>parentRect.bottom){parent.scrollTo({top:offsetTop-(parent.clientHeight-elementRect.height),...scrollOptions})}}
wrapTablesInDiv();window.addEventListener('scroll',onScroll);onScroll();TOCClicketEvents()}})